class Solution:
    def findMinimumRemovals(self, intervalList):
        if not intervalList:
            return 0

        # Sort by ending time
        intervalList.sort(key=lambda x: x[1])

        removals = 0
        end = intervalList[0][1]

        for i in range(1, len(intervalList)):
            if intervalList[i][0] < end:
                # Overlap → remove
                removals += 1
            else:
                # No overlap → update end
                end = intervalList[i][1]

        return removals

