int cmp(const void *a, const void *b) {
    Interval *x = (Interval *)a;
    Interval *y = (Interval *)b;
    return x->end - y->end;
}

int findMinimumRemovals(Interval *intervals, int n) {
    if (n == 0) return 0;

    qsort(intervals, n, sizeof(Interval), cmp);

    int removals = 0;
    int end = intervals[0].end;

    for (int i = 1; i < n; i++) {
        if (intervals[i].start < end) {
            // Overlap: remove interval
            removals++;
        } else {
            // No overlap: keep interval & update
            end = intervals[i].end;
        }
    }

    return removals;
}

