class Solution {
    public int findMinimumRemovals(List<int[]> intervalList) {
        if (intervalList.isEmpty()) return 0;

        // Sort by end time
        intervalList.sort((a, b) -> Integer.compare(a[1], b[1]));

        int removals = 0;
        int end = intervalList.get(0)[1];

        for (int i = 1; i < intervalList.size(); i++) {
            if (intervalList.get(i)[0] < end) {
                // Overlapping → remove
                removals++;
            } else {
                // No overlap → update end
                end = intervalList.get(i)[1];
            }
        }

        return removals;
    }
}

